# Compare expected vs actual output
import json

expected = [
    '{"rule_id":"if-statement","file":"main.py","language":"python","start":{"line":2,"col":5},"end":{"line":2,"col":18},"match":"print(\\"hello\\")","captures":{"$GREETING":{"text":"\\"hello\\"","ranges":[{"start":{"line":2,"col":11},"end":{"line":2,"col":18}}]}}}',
    '{"rule_id":"if-statement","file":"main.py","language":"python","start":{"line":4,"col":5},"end":{"line":4,"col":22},"match":"print(greeting())","captures":{"$GREETING":{"text":"greeting()","ranges":[{"start":{"line":4,"col":11},"end":{"line":4,"col":22}}]}}}',
    '{"rule_id":"log-with-same-tag","file":"web.js","language":"javascript","start":{"line":1,"col":1},"end":{"line":1,"col":27},"match":"console.log(\\"user\\", \\"user\\")","captures":{"$TAG":{"text":"\\"user\\"","ranges":[{"start":{"line":1,"col":13},"end":{"line":1,"col":19}},{"start":{"line":1,"col":21},"end":{"line":1,"col":27}}]}}}',
]

actual = [
    '{"rule_id":"if-statement","file":"main.py","language":"python","start":{"line":2,"col":5},"end":{"line":2,"col":19},"match":"print(\\"hello\\")","captures":{"$GREETING":{"text":"\\"hello\\"","ranges":[{"start":{"line":2,"col":11},"end":{"line":2,"col":18}}]}}}',
    '{"rule_id":"if-statement","file":"main.py","language":"python","start":{"line":4,"col":5},"end":{"line":4,"col":22},"match":"print(greeting())","captures":{"$GREETING":{"text":"greeting()","ranges":[{"start":{"line":4,"col":11},"end":{"line":4,"col":21}}]}}}',
    '{"rule_id":"log-with-same-tag","file":"web.js","language":"javascript","start":{"line":1,"col":1},"end":{"line":1,"col":28},"match":"console.log(\\"user\\", \\"user\\")","captures":{"$TAG":{"text":"\\"user\\"","ranges":[{"start":{"line":1,"col":13},"end":{"line":1,"col":19}},{"start":{"line":1,"col":21},"end":{"line":1,"col":27}}]}}}',
]

for i, (e, a) in enumerate(zip(expected, actual)):
    ej = json.loads(e)
    aj = json.loads(a)

    # Compare
    diffs = []
    for key in ['start', 'end', 'match']:
        if ej.get(key) != aj.get(key):
            diffs.append((key, ej.get(key), aj.get(key)))
    if 'captures' in ej and 'captures' in aj:
        for ckey in ej['captures']:
            ec = ej['captures'][ckey]
            ac = aj['captures'][ckey]
            for cpart in ['text', 'ranges']:
                if ec.get(cpart) != ac.get(cpart):
                    diffs.append((f'captures.{ckey}.{cpart}', ec.get(cpart), ac.get(cpart)))

    if diffs:
        print(f"Match {i+1} diffs:")
        for key, exp, act in diffs:
            print(f"  {key}: expected={exp}, actual={act}")
    else:
        print(f"Match {i+1}: OK")
